import sailpoint.object.*;
import sailpoint.api.*;
import sailpoint.tools.Util;


CertificationItem item = (CertificationItem) certContext.get("certificationItem");
if(item!=null @and item.getTargetId()!=null){
  List entitles = new ArrayList();
  Profile prof = context.getObjectById(Profile.class,item.getTargetId());
  if(prof!=null @and prof.getConstraints()!=null){
    List constrs = prof.getConstraints();
    if(constrs!=null){
      for(Filter filt : constrs){
        if(filt.getValue() instanceof String){
          Filter filter = Filter.and(Filter.eq("application.name",prof.getApplication().getName()),Filter.eq("value",filt.getValue()));
          ManagedAttribute group = context.getUniqueObject(ManagedAttribute.class,filter);
          if(group!=null){
            if(group.getDisplayName()!=null) entitles.add(group.getDisplayName()); 
            else entitles.add(filt.getValue());
            context.decache(group);
          }
        }
        else if(filt.getValue() instanceof List){
          Filter filter = Filter.and(Filter.eq("application.name",prof.getApplication().getName()),Filter.in("value",filt.getValue()));
          QueryOptions qo = new QueryOptions();
          qo.add(filter);
          List groups = context.getObjects(ManagedAttribute.class,qo);
          if(groups!=null){
            for(ManagedAttribute group : groups){
              if(group!=null){
                if(group.getDisplayName()!=null) entitles.add(group.getDisplayName()); 
                else entitles.add(filt.getValue());
                context.decache(group); 
              }
            }
          }
        }
      }
    }
  }
  item.setCustom1(Util.listToCsv(entitles));
}
return item;
